-- See what columns exist
SELECT column_name, data_type
FROM information_schema.columns
WHERE table_name = 'customers';

-- Peek at a few rows
SELECT * FROM customers LIMIT 5;

CREATE TABLE users (
  id SERIAL PRIMARY KEY,
  email VARCHAR(255) NOT NULL UNIQUE,
  name VARCHAR(255) NOT NULL,
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE rooms (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL,
  capacity INT NOT NULL CHECK (capacity > 0),
  floor INT NOT NULL
);

CREATE TABLE amenities (
  id SERIAL PRIMARY KEY,
  name VARCHAR(100) NOT NULL UNIQUE
);

CREATE TABLE room_amenities (
  room_id INT NOT NULL REFERENCES rooms(id) ON DELETE CASCADE,
  amenity_id INT NOT NULL REFERENCES amenities(id) ON DELETE CASCADE,
  PRIMARY KEY (room_id, amenity_id)
);

CREATE TABLE bookings (
  id SERIAL PRIMARY KEY,
  user_id INT NOT NULL REFERENCES users(id),
  room_id INT NOT NULL REFERENCES rooms(id),
  start_time TIMESTAMPTZ NOT NULL,
  end_time TIMESTAMPTZ NOT NULL,
  status VARCHAR(20) NOT NULL DEFAULT 'confirmed'
    CHECK (status IN ('confirmed', 'cancelled')),
  created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  CHECK (end_time > start_time)
);

-- UP migration
BEGIN;
  -- (DDL from above)
COMMIT;

-- DOWN migration
BEGIN;
  DROP TABLE IF EXISTS bookings;
  DROP TABLE IF EXISTS room_amenities;
  DROP TABLE IF EXISTS amenities;
  DROP TABLE IF EXISTS rooms;
  DROP TABLE IF EXISTS users;
COMMIT;

CREATE TABLE account_balance (
  account_id INT PRIMARY KEY,
  balance DECIMAL(10,2) NOT NULL
);
INSERT INTO account_balance VALUES (1, 1000.00);

-- Session A (READ COMMITTED):
BEGIN;
SELECT balance FROM account_balance WHERE account_id = 1;
-- Returns: 1000.00

-- Session B (in parallel):
UPDATE account_balance SET balance = 500.00 WHERE account_id = 1;
COMMIT;

-- Session A reads again:
SELECT balance FROM account_balance WHERE account_id = 1;
-- Returns: 500.00  <-- non-repeatable read!
COMMIT;

-- Now repeat with REPEATABLE READ:
-- Session A:
BEGIN ISOLATION LEVEL REPEATABLE READ;
SELECT balance FROM account_balance WHERE account_id = 1;
-- Returns: 1000.00 (after resetting)

-- Session B updates and commits...

-- Session A reads again:
SELECT balance FROM account_balance WHERE account_id = 1;
-- Still returns: 1000.00  <-- consistent!
COMMIT;
